package org.micahgruenwald.mandelbrotmultithread;
import java.awt.image.BufferedImage;
import java.io.File;
import java.io.IOException;

import javax.imageio.ImageIO;

class AppTest {
  public static void main(String[] args) {
    // testSingleMandelbrot();
    testManager();
  }

  public static void testSingleMandelbrot() {
    BufferedImage image = new BufferedImage(101, 101, BufferedImage.TYPE_INT_RGB);
    MandelbrotThread mandelbrot1 =
        new MandelbrotThread(-2.0, -1.25, .5, 1.25, 50, 0, 100,100, image);
    mandelbrot1.start();

    try {
      mandelbrot1.join();
      File outputfile =
          new File(
              "app/src/test/java/org/micahgruenwald/mandelbrotmultithread/testOutput/saved.png");
      ImageIO.write(image, "png", outputfile);
    } catch (IOException e) {
    } catch (InterruptedException e) {
      // TODO Auto-generated catch block
      e.printStackTrace();
    }
  }

  public static void testManager(){
    long ti = System.nanoTime();
        System.out.println("Processors: "+Runtime.getRuntime().availableProcessors());
    BufferedImage image = new BufferedImage(1000, 1000, BufferedImage.TYPE_INT_RGB);
    Calculator.setColorMode(ColorMode.ORANGE_BLACK_BLUE);
    Calculator.setJuliaValues( -0.4,  0.6, 2);
    Calculator.setMaxIterations(200);
    Calculator.setJuliaMode(true);
    Manager manager = new Manager(8, new RenderArea(0,0, 3.5,3.5), image);

    manager.start();
    try {
      manager.join();
      System.out.println("Runtime: " + (System.nanoTime() - ti) * 1e-9);
      File outputFile =
          new File(
              "app/src/test/java/org/micahgruenwald/mandelbrotmultithread/testOutput/saved.png");
      ImageIO.write(image, "png", outputFile);
    } catch (IOException | InterruptedException e) {
    }
  }
}
